#include <stdio.h>
#include <stdlib.h>
#include <string.h>

int rank_map[26];

int cmp_str(const void *a, const void *b) {
    const char *sa = *(const char **)a;
    const char *sb = *(const char **)b;
    while (*sa && *sb) {
        if (*sa != *sb) {
            int ra = rank_map[*sa - 'a'];
            int rb = rank_map[*sb - 'a'];
            return ra - rb; // smaller rank -> higher priority
        }
        sa++; sb++;
    }
    // one string ended
    return (int)strlen(sa) - (int)strlen(sb);
}

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        char S[27]; scanf("%s", S);
        for (int i=0;i<26;i++) rank_map[S[i]-'a'] = i;
        int N; scanf("%d", &N);
        char **arr = (char **)malloc(N * sizeof(char*));
        for (int i=0;i<N;i++) {
            char buf[101]; scanf("%s", buf);
            arr[i] = strdup(buf);
        }
        qsort(arr, N, sizeof(char*), cmp_str);
        for (int i=0;i<N;i++) {
            printf("%s\n", arr[i]);
            free(arr[i]);
        }
        free(arr);
    }
    return 0;
}

