#!/usr/bin/env python3
import sys
from functools import cmp_to_key

def solve():
    data = sys.stdin.read().splitlines()
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        S = next(it).strip()
        rank = {c: i for i, c in enumerate(S)}
        N = int(next(it))
        arr = [next(it).strip() for _ in range(N)]
        def cmp(a, b):
            la, lb = len(a), len(b)
            i = 0
            while i < la and i < lb:
                if a[i] != b[i]:
                    return -1 if rank[a[i]] < rank[b[i]] else 1
                i += 1
            return -1 if la < lb else (1 if la > lb else 0)
        arr.sort(key=cmp_to_key(cmp))
        out_lines.extend(arr)
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

